// src/App.js
import React, { useState, useEffect, useRef } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Calendar, momentLocalizer } from 'react-big-calendar';
import withDragAndDrop from 'react-big-calendar/lib/addons/dragAndDrop';
import 'react-big-calendar/lib/css/react-big-calendar.css';
import 'react-big-calendar/lib/addons/dragAndDrop/styles.css';
import './calendar-styles.css';
import dayjs from 'dayjs';
import utc from 'dayjs/plugin/utc';
import timezone from 'dayjs/plugin/timezone';
import moment from 'moment';
import 'moment/locale/ko';
import CustomToolbar from './CustomToolbar';
import Login from './components/Login';
import Register from './components/Register';
import ForgotPassword from './components/ForgotPassword';
import ResetPassword from './components/ResetPassword';
import PrivateRoute from './components/PrivateRoute';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import api from './services/api';

dayjs.extend(utc);
dayjs.extend(timezone);

const localizer = momentLocalizer(moment);
const DnDCalendar = withDragAndDrop(Calendar);

const pastelColors = [
  "#FFB3BA", "#FFDFBA", "#FFFFBA",
  "#BAFFC9", "#BAE1FF", "#C6B4FF", "#FFC6FF",
];
const CATEGORY_OPTIONS = [
  { value: 'school', label: '학업' },
  { value: 'housework', label: '집안일' },
  { value: 'work', label: '업무' },
  { value: 'selfdev', label: '자기계발' },
  { value: 'family', label: '가족' },
  { value: 'health', label: '건강' },
  { value: 'event', label: '이벤트' },
  { value: 'goal', label: '목표' },
];
const PRIORITY_OPTIONS = [
  { value: '높음', label: '높음' },
  { value: '보통', label: '보통' },
  { value: '낮음', label: '낮음' },
];
const TYPE_OPTIONS = [
  { value: 'general', label: '일반' },
  { value: 'deadline', label: '기한' },
  { value: 'repeat', label: '반복' },
];

// OpenAI API 호출 함수들
const classifyCategory = async (text) => {
  const apiKey = process.env.REACT_APP_OPENAI_API_KEY;
  console.log('API Key available:', !!apiKey); // API 키 존재 여부만 로깅

  if (!apiKey) {
    console.warn('OpenAI API 키가 설정되지 않았습니다. .env 파일을 확인해주세요.');
    return CATEGORY_OPTIONS[0].value;
  }

  try {
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${apiKey}`
      },
      body: JSON.stringify({
        model: "gpt-3.5-turbo",
        messages: [
          {
            role: "system",
            content: `다음 카테고리 중에서 가장 적절한 하나를 선택해주세요: ${CATEGORY_OPTIONS.map(opt => opt.label).join(', ')}. 
            응답은 반드시 주어진 카테고리 중 하나의 이름만 반환해야 합니다.`
          },
          {
            role: "user",
            content: text
          }
        ],
        temperature: 0.3,
        max_tokens: 10
      })
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      console.error('API 응답 오류:', response.status, errorData);
      throw new Error(`API 요청 실패: ${response.status}`);
    }

    const data = await response.json();
    if (!data.choices?.[0]?.message?.content) {
      throw new Error('API 응답 형식이 올바르지 않습니다.');
    }

    const category = data.choices[0].message.content.trim();
    const categoryOption = CATEGORY_OPTIONS.find(opt => opt.label === category);
    return categoryOption ? categoryOption.value : CATEGORY_OPTIONS[0].value;
  } catch (error) {
    console.error('카테고리 분류 중 오류:', error);
    return CATEGORY_OPTIONS[0].value;
  }
};

const generateTitle = async (text) => {
  const apiKey = process.env.REACT_APP_OPENAI_API_KEY;
  console.log('API Key available:', !!apiKey); // API 키 존재 여부만 로깅

  if (!apiKey) {
    console.warn('OpenAI API 키가 설정되지 않았습니다. .env 파일을 확인해주세요.');
    return text.length > 10 ? text.substring(0, 10) + '...' : text;
  }

  try {
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${apiKey}`
      },
      body: JSON.stringify({
        model: "gpt-3.5-turbo",
        messages: [
          {
            role: "system",
            content: `주어진 일정 내용을 간단하고 명확한 제목으로 요약해주세요. 
            제목은 10자 이내로 짧게 작성하고, 핵심 내용만 포함해야 합니다.
            응답은 제목만 반환하고 다른 설명은 포함하지 마세요.`
          },
          {
            role: "user",
            content: text
          }
        ],
        temperature: 0.3,
        max_tokens: 20
      })
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      console.error('API 응답 오류:', response.status, errorData);
      throw new Error(`API 요청 실패: ${response.status}`);
    }

    const data = await response.json();
    if (!data.choices?.[0]?.message?.content) {
      throw new Error('API 응답 형식이 올바르지 않습니다.');
    }

    return data.choices[0].message.content.trim();
  } catch (error) {
    console.error('제목 생성 중 오류:', error);
    return text.length > 10 ? text.substring(0, 10) + '...' : text;
  }
};

// Calendar component separated for use with PrivateRoute
function CalendarApp() {
  const { currentUser, logout } = useAuth();
  const [events, setEvents] = useState([]);
  const [currentDate, setCurrentDate] = useState(new Date());
  const [currentView, setCurrentView] = useState('week');
  const [transcript, setTranscript] = useState('');
  const [recording, setRecording] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [confirmText, setConfirmText] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [manualEvent, setManualEvent] = useState({
    date: '', startTime: '', endTime: '',
    title: '', memo: '', color: pastelColors[0],
    categoryCode: CATEGORY_OPTIONS[0].value,
    priority: PRIORITY_OPTIONS[1].value,
    type: TYPE_OPTIONS[0].value,
    isAllDay: false,
  });
  const [editMode, setEditMode] = useState(false);
  const [editEvent, setEditEvent] = useState(null);
  const [showEventModal, setShowEventModal] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const recognitionRef = useRef(null);

  // Load schedules
  useEffect(() => {
    (async () => {
      try {
        const data = await api.schedules.getAll();
        setEvents(data.map(item => ({
          id: item._id,
          _id: item._id,
          title: item.title,
          start: dayjs.utc(item.startTime).local().toDate(),
          end: dayjs.utc(item.endTime).local().toDate(),
          memo: item.description,
          color: item.color || pastelColors[0],
          categoryCode: item.categoryCode,
          priority: item.priority,
          type: item.type,
          isAllDay: item.isAllDay || false,
        })));
      } catch (err) {
        console.error('일정 불러오기 중 에러:', err);
        if (err.message === '인증 실패') {
          logout();
        }
      }
    })();
  }, [logout]);

  // Create schedule
  const createSchedule = async evt => {
    const body = {
      title: evt.title,
      description: evt.memo,
      startTime: evt.start.toISOString(),
      endTime: evt.end.toISOString(),
      dueDate: null,
      isRepeating: false,
      repeatPattern: null,
      categoryCode: evt.categoryCode,
      priority: evt.priority,
      type: evt.type,
      isCompleted: false,
      color: evt.color,
      isAllDay: evt.isAllDay || false,
    };
    const result = await api.schedules.create(body);
    return result.schedule;
  };

  // Update schedule
  const updateSchedule = async evt => {
    const body = {
      title: evt.title,
      description: evt.memo,
      startTime: evt.start.toISOString(),
      endTime: evt.end.toISOString(),
      categoryCode: evt.categoryCode,
      priority: evt.priority,
      type: evt.type,
      color: evt.color,
      isAllDay: evt.isAllDay || false,
    };
    return api.schedules.update(evt._id, body);
  };

  // Speech Recognition
  const startRecognition = () => {
    if (!('SpeechRecognition' in window || 'webkitSpeechRecognition' in window)) {
      setError('이 브라우저는 음성 인식을 지원하지 않습니다. Chrome 브라우저를 사용해주세요.');
      setShowModal(true);
      return;
    }

    try {
      const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
      const rec = new SR();

      rec.lang = 'ko-KR';
      rec.interimResults = false;
      rec.continuous = false;
      rec.maxAlternatives = 1;

      rec.onstart = () => {
        setRecording(true);
        setTranscript('');
        setError('');
        setShowModal(false);
      };

      rec.onresult = event => {
        const text = event.results[0][0].transcript;
        setTranscript(text);
      };

      rec.onerror = err => {
        setRecording(false);

        let errorMessage = '';
        switch(err.error) {
          case 'no-speech':
            errorMessage = '음성이 감지되지 않았습니다. 다시 시도해주세요.';
            break;
          case 'audio-capture':
            errorMessage = '마이크를 찾을 수 없습니다. 마이크가 연결되어 있는지 확인해주세요.';
            break;
          case 'not-allowed':
            errorMessage = '마이크 사용 권한이 필요합니다. 브라우저 설정에서 마이크 권한을 허용해주세요.';
            break;
          default:
            errorMessage = '음성 인식 중 오류가 발생했습니다. 다시 시도해주세요.';
        }

        setError(errorMessage);
        setShowModal(true);
        stopRecognition();
      };

      rec.onend = () => {
        setRecording(false);

        if (!transcript) {
          setError('음성이 인식되지 않았습니다. 다시 시도해주세요.');
          setShowModal(true);
          return;
        }

        // 음성 인식 결과를 모달에 표시
        setShowModal(true);
      };

      recognitionRef.current = rec;
      rec.start();
    } catch (err) {
      setError('음성 인식을 초기화하는 중 오류가 발생했습니다.');
      setShowModal(true);
    }
  };

  const stopRecognition = () => {
    if (recognitionRef.current) {
      recognitionRef.current.stop();
      setRecording(false);
    }
  };

  // Select slot -> manual add modal
  const handleSelectSlot = slotInfo => {
    const d = dayjs(slotInfo.start);
    setManualEvent({
      date: d.format('YYYY-MM-DD'),
      startTime: d.format('HH:mm'),
      endTime: d.add(1, 'hour').format('HH:mm'),
      title: '',
      memo: '',
      color: pastelColors[0],
      categoryCode: CATEGORY_OPTIONS[0].value,
      priority: PRIORITY_OPTIONS[1].value,
      type: TYPE_OPTIONS[0].value,
      isAllDay: false,
    });
    setShowModal(true);
  };

  const handleManualChange = e => {
    const { name, value, type, checked } = e.target;
    if (type === 'checkbox') {
      setManualEvent(prev => ({ ...prev, [name]: checked }));
    } else {
      setManualEvent(prev => ({ ...prev, [name]: value }));
    }
  };

  const handleManualSubmit = async e => {
    e.preventDefault();
    const { date, startTime, endTime, title, memo, color, categoryCode, priority, type, isAllDay } = manualEvent;
    if (!date || (!isAllDay && (!startTime || !endTime)) || !title) return;

    let start, end;
    if (isAllDay) {
      // 하루종일 이벤트인 경우 00:00부터 23:59까지로 설정
      start = dayjs.tz(`${date} 00:00`, 'YYYY-MM-DD HH:mm', 'Asia/Seoul').toDate();
      end = dayjs.tz(`${date} 23:59`, 'YYYY-MM-DD HH:mm', 'Asia/Seoul').toDate();
    } else {
      start = dayjs.tz(`${date} ${startTime}`, 'YYYY-MM-DD HH:mm', 'Asia/Seoul').toDate();
      end = dayjs.tz(`${date} ${endTime}`, 'YYYY-MM-DD HH:mm', 'Asia/Seoul').toDate();
    }

    const tmpId = `tmp-${Date.now()}`;
    const tmpEvt = { 
      id: tmpId, 
      title, 
      start, 
      end, 
      memo, 
      color, 
      categoryCode, 
      priority, 
      type,
      isAllDay 
    };
    setEvents(prev => [...prev, tmpEvt]);
    setShowModal(false);
    try {
      const saved = await createSchedule(tmpEvt);
      setEvents(prev => prev.map(ev => ev.id === tmpId ? { ...ev, id: saved._id, _id: saved._id } : ev));
    } catch (err) {
      console.error(err);
      setEvents(prev => prev.filter(ev => ev.id !== tmpId));
    }
  };

  // Event click -> view modal
  const handleSelectEvent = evt => {
    setSelectedEvent({
      ...evt,
      date: dayjs(evt.start).format('YYYY-MM-DD'),
      startTime: dayjs(evt.start).format('HH:mm'),
      endTime: dayjs(evt.end).format('HH:mm'),
      memo: evt.memo,
      color: evt.color,
      categoryCode: evt.categoryCode,
      priority: evt.priority,
      type: evt.type,
      isAllDay: evt.isAllDay || false,
    });
    setShowEventModal(true);
  };

  // Open edit modal from view modal
  const handleEditClick = () => {
    setEditEvent(selectedEvent);
    setShowEventModal(false);
    setEditMode(true);
  };

  // Delete event
  const handleDeleteEvent = async () => {
    try {
      if (!selectedEvent || !selectedEvent._id) return;

      await api.schedules.delete(selectedEvent._id);
      setEvents(prev => prev.filter(ev => ev.id !== selectedEvent.id));
      setShowEventModal(false);
    } catch (err) {
      console.error('일정 삭제 중 오류:', err);
    }
  };

  // 이벤트 정보 수정
  const handleEditChange = e => {
    const { name, value, type, checked } = e.target;
    if (type === 'checkbox') {
      setEditEvent(prev => ({ ...prev, [name]: checked }));
    } else {
      setEditEvent(prev => ({ ...prev, [name]: value }));
