  };

  // 음성 인식 일정 자동 등록
  const handleVoiceInputSchedule = async (text) => {
    try {
      if (!text || text.trim() === '') {
        throw new Error('음성이 인식되지 않았습니다.');
      }

      console.log('음성 인식 결과 처리 시작:', text);

      // 음성 인식 결과 분석
      let title = '';
      let startTime = '';
      let endTime = '';
      let category = CATEGORY_OPTIONS[0].value;
      let priority = PRIORITY_OPTIONS[1].value;
      let type = TYPE_OPTIONS[0].value;
      let memo = '';

      // 날짜/시간 추출
      const now = new Date();
      let date = new Date(now);

      // 상대적 날짜 처리
      if (text.includes('내일')) {
        date.setDate(date.getDate() + 1);
      } else if (text.includes('모레')) {
        date.setDate(date.getDate() + 2);
      } else if (text.includes('글피')) {
        date.setDate(date.getDate() + 3);
      } else {
        // 절대적 날짜 처리
        const dateMatch = text.match(/(\d{1,2}월\s*\d{1,2}일|\d{1,2}일)/);
        if (dateMatch) {
          const dateStr = dateMatch[0].replace(/\s+/g, '');
          const [month, day] = dateStr.split('월').map(s => parseInt(s));
          date = new Date(now.getFullYear(), month - 1, day);
        }
      }

      // 시간 추출 및 처리
      const timeMatch = text.match(/(\d{1,2})시/);
      if (timeMatch) {
        let hour = parseInt(timeMatch[1]);

        // 오전/오후 처리
        if (text.includes('오전') || text.includes('아침')) {
          // 오전은 그대로
        } else if (text.includes('오후') || text.includes('저녁')) {
          hour = hour + 12;
        } else {
          // 오전/오후가 명시되지 않은 경우
          // 1~6시는 오후로, 7~12시는 오전으로 가정
          if (hour >= 1 && hour <= 6) {
            hour = hour + 12;
          }
        }

        startTime = new Date(date);
        startTime.setHours(hour, 0, 0);

        endTime = new Date(date);
        endTime.setHours(hour + 1, 0, 0);
      } else {
        // 시간이 지정되지 않은 경우 현재 시간으로 설정
        startTime = new Date(date);
        startTime.setHours(now.getHours(), 0, 0);

        endTime = new Date(date);
        endTime.setHours(now.getHours() + 1, 0, 0);
      }

      console.log('추출된 시간 정보:', {
        date: date.toISOString(),
        startTime: startTime.toISOString(),
        endTime: endTime.toISOString()
      });

      // 원본 텍스트에서 날짜/시간 정보 제거
      const cleanText = text
        .replace(/내일|모레|글피/g, '')
        .replace(/(\d{1,2}월\s*\d{1,2}일|\d{1,2}일)/g, '')
        .replace(/(\d{1,2}시|\d{1,2}:\d{2})/g, '')
        .replace(/오전|오후|아침|저녁/g, '')
        .trim();

      console.log('정제된 텍스트:', cleanText);

      // OpenAI를 사용하여 제목 생성 및 카테고리 분류
      const [generatedTitle, classifiedCategory] = await Promise.all([
        generateTitle(cleanText),
        classifyCategory(cleanText)
      ]);

      title = generatedTitle;
      category = classifiedCategory;

      console.log('생성된 정보:', {
        title,
        category,
        cleanText
      });

      // 수정 모달에 표시할 데이터 설정
      const editData = {
        title,
        date: startTime ? dayjs(startTime).format('YYYY-MM-DD') : dayjs(date).format('YYYY-MM-DD'),
        startTime: startTime ? dayjs(startTime).format('HH:mm') : dayjs().format('HH:mm'),
        endTime: endTime ? dayjs(endTime).format('HH:mm') : dayjs().add(1, 'hour').format('HH:mm'),
        memo: cleanText, // 원본 텍스트를 메모로 저장
        color: pastelColors[Math.floor(Math.random() * pastelColors.length)],
        categoryCode: category,
        priority,
        type,
        isAllDay: false,
      };

      console.log('최종 일정 데이터:', editData);

      // 바로 수정 모달 열기
      setEditEvent(editData);
      setEditMode(true);
      setShowModal(false);
      setError('');
      setTranscript('');

    } catch (err) {
      console.error('일정 생성 중 오류:', err);
      setError(err.message || '음성 입력을 처리하는 중 오류가 발생했습니다.');
      setShowModal(true);
    }
  };

